# AUTOGENERATED! DO NOT EDIT!

def compute_cosine_similarity(onet_descriptions, onet_embeddings, job_ad_embeddings, ctx, print) -> {"candidates": dict}:
    """Compute top-K cosine similarity matches between job ads and O*NET occupations."""
    from ai_index.utils import maybe_run_remote
    
    remote_result = maybe_run_remote(
        func_path="ai_index.nodes.compute_cosine_similarity.compute_cosine_similarity",
        inputs={"onet_descriptions": onet_descriptions, "onet_embeddings": onet_embeddings, "job_ad_embeddings": job_ad_embeddings},
        ctx=ctx, print_fn=print,
        job_name="compute_cosine_similarity", time="01:00:00",
    )
    if remote_result is not None:
        return remote_result
    import numpy as np
    
    execution_mode = ctx.vars.get("execution_mode", "local")
    
    top_k = ctx.vars.get("cosine_top_k", 5)
    batch_size = ctx.vars.get("cosine_batch_size", 16384)
    
    # Extract data — titles from onet_embeddings to guarantee index alignment
    onet_titles = onet_embeddings["titles"]
    onet_role = np.asarray(onet_embeddings["role_embeddings"])   # (M, D)
    onet_task = np.asarray(onet_embeddings["task_embeddings"])   # (M, D)
    
    job_ids = job_ad_embeddings["job_ids"]
    job_role = np.asarray(job_ad_embeddings["role_embeddings"])  # (N, D)
    job_task = np.asarray(job_ad_embeddings["task_embeddings"])  # (N, D)
    
    n_jobs = len(job_ids)
    n_onet = len(onet_titles)
    print(f"compute_cosine_similarity: {n_jobs} jobs x {n_onet} occupations, top_k={top_k}, batch_size={batch_size}, mode={execution_mode}")
    # L2-normalize in float32 for numerical accuracy
    def _l2_normalize(arr):
        arr = arr.astype(np.float32)
        norms = np.linalg.norm(arr, axis=1, keepdims=True)
        norms = np.maximum(norms, 1e-12)
        return arr / norms
    
    onet_role_norm = _l2_normalize(onet_role)
    onet_task_norm = _l2_normalize(onet_task)
    job_role_norm = _l2_normalize(job_role)
    job_task_norm = _l2_normalize(job_task)
    # Merge helper — shared between CPU and GPU paths
    def _merge_topk(role_indices, role_scores, task_indices, task_scores, onet_titles, batch_size_actual):
        """Merge role and task top-K results into combined candidates."""
        candidates = []
        for j in range(batch_size_actual):
            combined = {}
            for idx, score in zip(role_indices[j], role_scores[j]):
                title = onet_titles[idx]
                combined.setdefault(title, []).append(float(score))
            for idx, score in zip(task_indices[j], task_scores[j]):
                title = onet_titles[idx]
                combined.setdefault(title, []).append(float(score))
    
            merged = [(title, sum(vals) / len(vals)) for title, vals in combined.items()]
            merged.sort(key=lambda x: x[1], reverse=True)
            candidates.append(merged)
        return candidates
    all_candidates = []
    
    if execution_mode == "api":
        # CPU-only numpy path — np.dot for similarity, np.argpartition for top-K
        k = min(top_k, n_onet)
        onet_role_norm_T = onet_role_norm.T  # (D, M)
        onet_task_norm_T = onet_task_norm.T  # (D, M)
    
        for i in range(0, n_jobs, batch_size):
            end = min(i + batch_size, n_jobs)
    
            # Role similarity: (batch, D) @ (D, M) -> (batch, M)
            sim_role = job_role_norm[i:end] @ onet_role_norm_T
            # Top-K via argpartition (faster than full sort for large M)
            topk_role_idx = np.argpartition(sim_role, -k, axis=1)[:, -k:]
            topk_role_scores = np.take_along_axis(sim_role, topk_role_idx, axis=1)
            # Sort the top-K by score descending
            sort_order = np.argsort(-topk_role_scores, axis=1)
            topk_role_idx = np.take_along_axis(topk_role_idx, sort_order, axis=1)
            topk_role_scores = np.take_along_axis(topk_role_scores, sort_order, axis=1)
    
            # Task similarity
            sim_task = job_task_norm[i:end] @ onet_task_norm_T
            topk_task_idx = np.argpartition(sim_task, -k, axis=1)[:, -k:]
            topk_task_scores = np.take_along_axis(sim_task, topk_task_idx, axis=1)
            sort_order = np.argsort(-topk_task_scores, axis=1)
            topk_task_idx = np.take_along_axis(topk_task_idx, sort_order, axis=1)
            topk_task_scores = np.take_along_axis(topk_task_scores, sort_order, axis=1)
    
            batch_cands = _merge_topk(
                topk_role_idx, topk_role_scores,
                topk_task_idx, topk_task_scores,
                onet_titles, end - i,
            )
            all_candidates.extend(batch_cands)
    
            if (i // batch_size) % 10 == 0 or end == n_jobs:
                print(f"  cosine (cpu): {end}/{n_jobs} jobs processed")
    
    else:
        # GPU path using torch
        import torch
    
        device = torch.device("cuda")
        onet_role_t = torch.from_numpy(onet_role_norm).to(device=device, dtype=torch.float16)  # (M, D)
        onet_task_t = torch.from_numpy(onet_task_norm).to(device=device, dtype=torch.float16)  # (M, D)
    
        for i in range(0, n_jobs, batch_size):
            end = min(i + batch_size, n_jobs)
    
            # Role similarity: (batch, D) @ (D, M) -> (batch, M)
            job_role_batch = torch.from_numpy(job_role_norm[i:end]).to(device=device, dtype=torch.float16)
            sim_role = job_role_batch @ onet_role_t.T
            topk_role_scores, topk_role_idx = torch.topk(sim_role, k=min(top_k, n_onet), dim=1)
    
            # Task similarity
            job_task_batch = torch.from_numpy(job_task_norm[i:end]).to(device=device, dtype=torch.float16)
            sim_task = job_task_batch @ onet_task_t.T
            topk_task_scores, topk_task_idx = torch.topk(sim_task, k=min(top_k, n_onet), dim=1)
    
            # Move to CPU for merge
            role_scores = topk_role_scores.cpu().numpy().astype(np.float32)
            role_indices = topk_role_idx.cpu().numpy()
            task_scores = topk_task_scores.cpu().numpy().astype(np.float32)
            task_indices = topk_task_idx.cpu().numpy()
    
            batch_cands = _merge_topk(
                role_indices, role_scores,
                task_indices, task_scores,
                onet_titles, end - i,
            )
            all_candidates.extend(batch_cands)
    
            if (i // batch_size) % 10 == 0 or end == n_jobs:
                print(f"  cosine (gpu): {end}/{n_jobs} jobs processed")
    
    print(f"compute_cosine_similarity: done — {n_jobs} jobs, avg candidates per job: {sum(len(c) for c in all_candidates) / max(n_jobs, 1):.1f}")
    return {"candidates": {
        "job_ids": job_ids,
        "candidates": all_candidates,
    }}
